import React, { useEffect, useState } from "react";
import {
  getMenu,
  agregarProducto,
  eliminarProducto,
  editarProducto,
  Producto,
} from "../../services/menuService";

const MenuAdmin: React.FC = () => {
  const [menu, setMenu] = useState<Producto[]>([]);
  const [nombre, setNombre] = useState("");
  const [categoria, setCategoria] = useState("");
  const [precio, setPrecio] = useState("");
  const [mensaje, setMensaje] = useState<string | null>(null);

  const cargarMenu = async () => {
    try {
      setMenu(await getMenu());
    } catch (e: any) {
      setMensaje(e.message);
    }
  };

  useEffect(() => {
    cargarMenu();
  }, []);

  const handleAgregar = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      await agregarProducto({ nombre, categoria, precio: parseFloat(precio) });
      setMensaje("¡Producto agregado!");
      setNombre("");
      setCategoria("");
      setPrecio("");
      cargarMenu();
    } catch (e: any) {
      setMensaje("Error: " + e.message);
    }
  };

  const handleEliminar = async (id: number) => {
    if (!window.confirm("¿Seguro que deseas eliminar este producto?")) return;
    try {
      await eliminarProducto(id);
      setMensaje("Producto eliminado.");
      cargarMenu();
    } catch (e: any) {
      setMensaje("Error: " + e.message);
    }
  };

  const handleEditar = async (producto: Producto) => {
    const nuevoNombre = prompt("Nuevo nombre:", producto.nombre);
    if (nuevoNombre === null) return;
    const nuevaCategoria = prompt("Nueva categoría:", producto.categoria);
    if (nuevaCategoria === null) return;
    const nuevoPrecio = prompt("Nuevo precio:", producto.precio.toString());
    if (nuevoPrecio === null) return;
    try {
      await editarProducto(producto.id, {
        nombre: nuevoNombre,
        categoria: nuevaCategoria,
        precio: parseFloat(nuevoPrecio),
      });
      setMensaje("Producto actualizado.");
      cargarMenu();
    } catch (e: any) {
      setMensaje("Error: " + e.message);
    }
  };

  return (
    <div className="max-w-4xl mx-auto">
      <div className="bg-white rounded-lg shadow-lg p-6">
        <h2 className="text-2xl font-bold text-gray-800 mb-6">
          🍽️ Gestión de Menú
        </h2>

        {mensaje && (
          <div className="bg-blue-50 border border-blue-200 text-blue-700 px-4 py-3 rounded-md mb-6">
            {mensaje}
          </div>
        )}

        <form
          onSubmit={handleAgregar}
          className="grid grid-cols-1 md:grid-cols-4 gap-4 mb-8"
        >
          <input
            value={nombre}
            onChange={(e) => setNombre(e.target.value)}
            placeholder="Nombre del plato"
            className="px-4 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
            required
          />
          <input
            value={categoria}
            onChange={(e) => setCategoria(e.target.value)}
            placeholder="Categoría"
            className="px-4 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
            required
          />
          <input
            value={precio}
            onChange={(e) => setPrecio(e.target.value)}
            placeholder="Precio"
            type="number"
            step="0.01"
            className="px-4 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
            required
          />
          <button
            type="submit"
            className="bg-green-500 hover:bg-green-600 text-white px-6 py-2 rounded-lg font-semibold transition-colors"
          >
            Agregar Plato
          </button>
        </form>

        <div className="space-y-4">
          {menu.map((item) => (
            <div
              key={item.id}
              className="bg-gray-50 border border-gray-200 rounded-lg p-4"
            >
              <div className="flex items-center justify-between">
                <div className="flex-1">
                  <h3 className="font-semibold text-gray-800 text-lg">
                    {item.nombre}
                  </h3>
                  <p className="text-sm text-gray-600">{item.categoria}</p>
                  <p className="text-xl font-bold text-green-600">
                    ${item.precio.toFixed(2)}
                  </p>
                </div>
                <div className="flex gap-2">
                  <button
                    onClick={() => handleEditar(item)}
                    className="bg-yellow-500 hover:bg-yellow-600 text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors"
                  >
                    Editar
                  </button>
                  <button
                    onClick={() => handleEliminar(item.id)}
                    className="bg-red-500 hover:bg-red-600 text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors"
                  >
                    Eliminar
                  </button>
                </div>
              </div>
            </div>
          ))}
        </div>

        {menu.length === 0 && (
          <div className="text-center py-12">
            <div className="text-6xl mb-4">🍽️</div>
            <h3 className="text-xl font-semibold text-gray-800 mb-2">
              No hay productos en el menú
            </h3>
            <p className="text-gray-600">Agrega el primer plato para empezar</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default MenuAdmin;
